const item = context.item.data;
const itemId = item?.id;
const itemType = item?.item_type;

function getSlots(i) {
  const q = i?.quantity ?? 0;
  const b = i?.bulk_type;

  if (q <= 0 || b === "none") return 0;
  if (b === "light") return Math.ceil(q / 5);
  if (b === "medium") return q * 2;
  if (b === "heavy") return q * 3;

  return 0;
}

// 1. Regola armatura: massimo una armatura in Pronto
if (itemType === "armor") {
  const otherReadyArmors = (collections.character_inventory_list?.data ?? []).filter(
    i =>
      i.location === "ready" &&
      i.item_type === "armor" &&
      i.id !== itemId
  );

  return otherReadyArmors.length === 0;
}

// 2. Regola normale: gli oggetti NON armatura non possono far superare 5 slot
const readyNonArmorItems = (collections.character_inventory_list?.data ?? []).filter(
  i =>
    i.location === "ready" &&
    i.item_type !== "armor" &&
    i.id !== itemId
);

const currentReadySlots = readyNonArmorItems.reduce(
  (sum, i) => sum + getSlots(i),
  0
);

const movingItemSlots = getSlots(item);

return currentReadySlots + movingItemSlots <= 5;

