const row = (collections.character_abilities_list?.data ?? []).find(
  ca =>
    String(ca.character_id) === String(variables.selected_character_id) &&
    String(ca.ability_id) === String(context.item.data?.['id'])
);

const ppSpent = Number(row?.pp_spent ?? 0);
const hasAdvantage = row?.has_advantage === true;
const hasDisadvantage = row?.has_disadvantage === true;
const basePool = Number(context.item.data?.['base_pool'] ?? 0);

const rawWounds = collections.character_wounds?.data;

const woundRows = Array.isArray(rawWounds)
  ? rawWounds
  : Array.isArray(rawWounds?.data)
    ? rawWounds.data
    : [];

const wounds = woundRows.find(
  w => String(w.character_id) === String(variables.selected_character_id)
);

const woundPenalty =
  (wounds?.light_locked === true && (wounds?.light_max ?? 0) > 0 ? 1 : 0)
  + (wounds?.moderate_locked === true && (wounds?.moderate_max ?? 0) > 0 ? 1 : 0)
  + (wounds?.grave_locked === true && (wounds?.grave_max ?? 0) > 0 ? 1 : 0)
  + (wounds?.critical_locked === true && (wounds?.critical_max ?? 0) > 0 ? 1 : 0);

let pool = basePool + ppSpent;

if (hasAdvantage) pool += 1;
if (hasDisadvantage) pool -= 1;

pool -= woundPenalty;

pool = Math.max(pool, 0);

return pool + "d6";

