  .filter(ca => ca.character_id === variables.selected_character_id);

const selectedStats = variables.filter_stats ?? [];
const selectedCategories = variables.filter_categories ?? [];

return abilities.filter(ability => {
  const characterAbility = characterAbilities.find(
    ca => ca.ability_id === ability.id
  );

  const matchesAcquired =
    !variables.filter_acquired || (characterAbility?.pp_spent ?? 0) > 0;

  const matchesFavorites =
    !variables.filter_favorites || characterAbility?.is_favorite;

  const matchesStats =
    selectedStats.length === 0 || selectedStats.includes(ability.stat_ref);

  const matchesCategories =
    selectedCategories.length === 0 || selectedCategories.includes(ability.category);

  return (
    matchesAcquired &&
    matchesFavorites &&
    matchesStats &&
    matchesCategories
  );
});

