const getRows = (raw) => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : [];

const talents = getRows(collections.talents?.data);
const characterTalents = getRows(collections.character_talents?.data);

const favoritesOnly = variables.talent_filter_favorites_only === true;
const acquiredOnly = variables.talent_filter_acquired_only === true;

const selectedCategories = Array.isArray(variables.talent_filter_categories)
  ? variables.talent_filter_categories.map(String)
  : [];

const selectedLevels = Array.isArray(variables.talent_filter_levels)
  ? variables.talent_filter_levels.map(v => Number(v)).filter(Number.isFinite)
  : [];

function getCharacterTalent(talent) {
  return characterTalents.find(ct =>
    String(ct.talent_id) === String(talent.id)
  );
}

function isFavorite(talent) {
  const row = getCharacterTalent(talent);
  return row?.is_favorite === true;
}

function isAcquired(talent) {
  const row = getCharacterTalent(talent);
  return Number(row?.current_rank ?? 0) > 0;
}

function matchesCategory(talent) {
  if (selectedCategories.length === 0) return true;

  return selectedCategories.includes(String(talent.type_key ?? ""));
}

function matchesLevel(talent) {
  if (selectedLevels.length === 0) return true;

  const start = Number(talent.talent_level ?? 1);
  const maxRank = Number(talent.max_rank ?? 1);
  const end = start + maxRank - 1;

  return selectedLevels.some(level =>
    level >= start && level <= end
  );
}

return talents
  .filter(t => t.is_active !== false)
  .filter(t => !favoritesOnly || isFavorite(t))
  .filter(t => !acquiredOnly || isAcquired(t))
  .filter(matchesCategory)
  .filter(matchesLevel)
  .sort((a, b) => {
    const orderA = Number(a.sort_order ?? 0);
    const orderB = Number(b.sort_order ?? 0);

    if (orderA !== orderB) return orderA - orderB;

    return String(a.name ?? "").localeCompare(String(b.name ?? ""));
  });

