const errors = [];

const volume = variables.substance_volume;
const min = variables.substance_intensity_min;
const max = variables.substance_intensity_max;

const conditionKey = variables.substance_condition_key;
const conditionSign = variables.substance_condition_sign;
const conditionLevel = Number(variables.substance_condition_level ?? 0);
const target1 = variables.substance_condition_target_1;
const target2 = variables.substance_condition_target_2;

const intensityValue = {
  nessuna: 0,
  lieve: 1,
  moderata: 2,
  grave: 3,
  critica: 4,
  potente: 5,
  superiore: 6
};

if (!variables.substance_name) errors.push("Inserisci il nome della sostanza.");
if (!volume) errors.push("Seleziona il Volume.");
if (!variables.substance_fattura) errors.push("Seleziona la Fattura.");
if (!variables.substance_portata) errors.push("Seleziona la Portata.");
if (!variables.substance_durata) errors.push("Seleziona la Durata.");
if (!variables.substance_bersaglio) errors.push("Seleziona il Bersaglio.");
if (!min) errors.push("Seleziona la Ferita minima.");
if (!max) errors.push("Seleziona la Ferita massima.");

if (["enorme", "colossale"].includes(volume)) {
  errors.push("Non puoi inserire in inventario una sostanza con Volume Enorme o Colossale.");
}

if (min && max && intensityValue[max] < intensityValue[min]) {
  errors.push("La Ferita massima non può essere inferiore alla Ferita minima.");
}

if (target1 && target2 && target1 === target2) {
  errors.push("Target 1 e Target 2 non possono essere uguali.");
}

const noSign = ["portato", "prono", "inefficiente", "trattenuto"];
const needsSign = !!conditionKey && !noSign.includes(conditionKey);

const needsTarget1 =
  (conditionKey === "abile" && conditionLevel >= 1) ||
  (conditionKey === "mobile" && conditionLevel >= 1) ||
  (conditionKey === "protetto" && conditionLevel >= 4);

const needsTarget2 =
  conditionKey === "abile" && conditionLevel >= 4;

if (conditionKey && conditionLevel <= 0) {
  errors.push("Se scegli una Condizione, devi scegliere anche il Livello.");
}

if (needsSign && !conditionSign) {
  errors.push("Questa Condizione richiede un Segno.");
}

if (needsTarget1 && !target1) {
  errors.push("Questa Condizione richiede Target 1.");
}

if (needsTarget2 && !target2) {
  errors.push("Questa Condizione richiede Target 2.");
}

return errors[0] ?? "";

