const renderSingularity = (singularityId, role = "standard") => {
  const itemId = String(variables.selected_inventory_item_id ?? "");

  const s = (collections.inventory_item_singularities?.data ?? []).find(
    x =>
      String(x.inventory_item_id ?? "") === itemId &&
      x.singularity_id === singularityId &&
      x.role === role
  );

  if (!s) return "";

  const item = (collections.character_inventory_list?.data ?? []).find(
    i => String(i.id ?? "") === itemId
  );

  const ctx =
    item?.item_type === "powerful" && item?.combat_relevant
      ? "weapon"
      : item?.item_type === "powerful"
      ? "substance"
      : "generic";

  const d = (collections.singularity_level_descriptions?.data ?? []).find(
    x =>
      x.singularity_id === singularityId &&
      x.level_key === s.level_key &&
      (x.context === ctx || x.context === "generic")
  );

  const displayKey =
    singularityId === "intensita" && role === "min"
      ? "intensita_min"
      : singularityId === "intensita" && role === "max"
      ? "intensita_max"
      : singularityId === "intensita" && role === "condition"
      ? "intensita_condition"
      : singularityId;

  const labelMap = {
    volume: "Volume",
    fattura: "Fattura",
    portata: "Portata",
    durata: "Durata",
    bersaglio: "Bersaglio",
    intensita_min: "Ferita minima",
    intensita_max: "Ferita massima",
    intensita_condition: "Condizione"
  };

  const label = labelMap[displayKey] ?? singularityId;

  // 🔴 QUI LA DIFFERENZA
  const showDescription =
    !(singularityId === "intensita" && (role === "min" || role === "max"));

  return `<span style="font-size:14px; color:white">
    <b>${label} (${s.value})</b>: ${d?.label ?? s.level_key}${
      showDescription && d?.description
        ? ` <span style="color:#A6A6A6; font-style:italic">(${d.description})</span>`
        : ""
    }
  </span>`;
};

return renderSingularity("portata");

